#!run
export async function main(){
  run.call(this);
  if(await this.input("Sure?")==="y"){
     run.call(this,true);
     this.echo("deleted");
  }
}
function run(wet){
  const d=this.resolve(".");
  for(let f of d.recursive()){
    if(f.endsWith(".d.ts"))continue;
    if(f.endsWith(".ts")||
    f.endsWith(".mjs")||
    f.endsWith(".cjs")||
    f.endsWith(".js")||
    f.endsWith(".js.map")){
      if(wet){
        //this.echo(f)
        f.rm();
      }else{
        this.echo("rm",f.relPath(d));
      }
    }
    
  }
}